type ApiState<T> =
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; message: string };

function render<T>(state: ApiState<T>): string {
  switch (state.status) {
    case 'loading': return 'Chargement...';
    case 'success': return JSON.stringify(state.data); // state.data est T ici
    case 'error':   return `Erreur: ${state.message}`; // state.message est string
    default: {
      const _exhaustive: never = state; // erreur si un cas manque
      return '';
    }
  }
}

