@RestController
public class FileController {

    @PostMapping("/api/files"
               , consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<FileResponse> upload(
            @RequestParam("file") MultipartFile file,
            @RequestParam("description") String description) throws IOException {

        if (file.isEmpty()) throw new BadRequestException("Fichier vide");

        String contentType = file.getContentType();
        if (!Set.of("image/jpeg", "image/png", "application/pdf").contains(contentType)) {
            throw new BadRequestException("Type non autorisé: " + contentType);
        }

        String filename = fileService.store(file);
        return ResponseEntity.created(URI.create("/api/files/" + filename))
                             .body(new FileResponse(filename, file.getSize()));
    }
}

