@Service
public class PaymentService {

    @CircuitBreaker(name = "paymentService", fallbackMethod = "paymentFallback")
    @Retry(name = "paymentService")
    public PaymentResult processPayment(PaymentRequest request) {
        return paymentClient.process(request); // appel HTTP externe
    }

    private PaymentResult paymentFallback(PaymentRequest request, Exception ex) {
        return PaymentResult.pending("Service temporairement indisponible");
    }
}

@PostMapping("/api/payments")
public ResponseEntity<PaymentDto> createPayment(
        @RequestHeader("Idempotency-Key") String idempotencyKey,
        @RequestBody @Valid PaymentRequest request) {

    // Chercher si cette clé a déjà été traitée
    Optional<PaymentDto> existing = paymentCache.get(idempotencyKey);
    if (existing.isPresent()) {
        return ResponseEntity.ok(existing.get()); // rejouer la réponse originale
    }

    // Traiter le paiement
    PaymentDto result = paymentService.process(request);

    // Stocker le résultat avec TTL (24h)
    paymentCache.put(idempotencyKey, result, Duration.ofHours(24));

    return ResponseEntity.status(HttpStatus.CREATED).body(result);
}

