// Recherche binaire — tableau TRIÉ obligatoire
public static int binarySearch(int[] sorted, int target) {
    int left = 0, right = sorted.length - 1;

    while (left <= right) {
        int mid = left + (right - left) / 2; // évite l'overflow
        if (sorted[mid] == target) return mid;
        if (sorted[mid] < target)  left = mid + 1;  // éliminer moitié gauche
        else                       right = mid - 1; // éliminer moitié droite
    }
    return -1; // non trouvé
}
// Arrays.binarySearch(sorted, target) en Java standard

