// Fibonacci récursif naïf : O(2ⁿ) temps, O(n) espace (pile)
int fib(int n) {
    if (n <= 1) return n;
    return fib(n - 1) + fib(n - 2); // calcule fib(30) deux fois !
}

// Fibonacci avec mémoïsation : O(n) temps, O(n) espace
int fib(int n, Map<Integer, Integer> memo) {
    if (n <= 1) return n;
    if (memo.containsKey(n)) return memo.get(n); // cache hit
    int result = fib(n - 1, memo) + fib(n - 2, memo);
    memo.put(n, result); // stocker pour réutilisation
    return result;
}

// Fibonacci itératif : O(n) temps, O(1) espace
int fib(int n) {
    if (n <= 1) return n;
    int a = 0, b = 1;
    for (int i = 2; i <= n; i++) { int c = a + b; a = b; b = c; }
    return b;
}

